fn mine_and_synthesize_feedback(
    plan: &SessionStorePlan,
    session_store_root: &Path,
) -> Result<(), String> {
    if plan.record.turns.is_empty() {
        return Ok(());
    }

    let workspace_root = session_store_root
        .parent()
        .unwrap_or(session_store_root)
        .to_path_buf();
    let feedback_root =
        memory_api::workspace::resolve_local_root_from(&workspace_root, ".feedback");
    let rule_root =
        memory_api::workspace::resolve_local_root_from(&workspace_root, ".rule");
    let ticket_root =
        memory_api::workspace::resolve_local_root_from(&workspace_root, ".ticket");

    let feedback_store = EntityFeedbackStore::new(
        feedback_root,
        plan.record.metadata.workspace_slug.clone(),
    )?;
    let rule_store = RuleStore::open_or_init(&rule_root)
        .map_err(|error| error.to_string())?;
    let ticket_store = TicketStore::open_or_init(&ticket_root)
        .map_err(|error| error.to_string())?;

    let rules: Vec<(String, String)> = rule_store
        .list(&RuleFilter::default(), None)
        .map_err(|error| error.to_string())?
        .into_iter()
        .filter_map(|rule| {
            rule.body()
                .map(|body| (rule.id.to_string(), body.to_string()))
        })
        .collect();
    if rules.is_empty() {
        return Ok(());
    }

    let author =
        IngestAuthor::privileged_agent("copilot-capture-hook")?;
    let mined = mine_transcript_for_rule_confusion(
        &feedback_store,
        &author,
        &plan.record.turns,
        &rules,
    )?;
    if mined.is_empty() {
        return Ok(());
    }

    synthesize_follow_up_tickets(
        &feedback_store,
        &rule_store,
        &ticket_store,
        &workspace_root,
        &plan.record.session_id,
        &mined,
    )
}

fn synthesize_follow_up_tickets(
    feedback_store: &EntityFeedbackStore,
    rule_store: &RuleStore,
    ticket_store: &TicketStore,
    workspace_root: &Path,
    session_id: &str,
    mined: &[MiningFeedbackResult],
) -> Result<(), String> {
    let mut seen_rules = BTreeSet::new();

    for urn in mined.iter().filter_map(|result| result.target_entity_urn.as_ref()) {
        if urn.store() != "rule" || !seen_rules.insert(urn.entity().to_string()) {
            continue;
        }

        let entries = feedback_store.entries_for(urn)?;
        let mined_count = entries
            .iter()
            .filter(|entry| entry.source == FeedbackSource::TranscriptMined)
            .count();
        if mined_count == 0 {
            continue;
        }

        let rule = rule_store.get(urn.entity()).map_err(|error| error.to_string())?;
        let rule_label = rule.slug().or(rule.title()).unwrap_or(urn.entity());
        let title = format!(
            "[feedback-loop] Investigate transcript-mined rule confusion for {}",
            rule_label
        );

        let duplicate = ticket_store
            .list(None, Some("tracker-improvement"), None)
            .map_err(|error| error.to_string())?
            .into_iter()
            .any(|ticket| ticket.title.as_deref() == Some(title.as_str()));
        if duplicate {
            continue;
        }

        let mut extra = BTreeMap::new();
        extra.insert(
            "priority".to_string(),
            serde_json::Value::String("medium".to_string()),
        );
        let description = format!(
            "Transcript mining opened this follow-up after session `{session_id}`.\n\nRule id: `{}`\nRule title: `{}`\nRule slug: `{}`\nTranscript-mined feedback entries for this rule: {}\n\nExpected next step: inspect the mined feedback entries under `{}` and decide whether the rule body or surrounding guidance needs refinement.",
            rule.id,
            rule.title().unwrap_or("(untitled)"),
            rule.slug().unwrap_or("(no slug)"),
            mined_count,
            urn.as_str(),
        );

        ticket_store
            .create(
                None,
                "tracker-improvement",
                Some(&title),
                Some("new"),
                extra,
                Some(workspace_root),
                Some(&description),
            )
            .map_err(|error| error.to_string())?;
    }

    Ok(())
}

