                    error
                )],
            )
        },
    };

    let mut verified_spec_ids = Vec::new();
    let mut errors = Vec::new();

    for spec_id in spec_ids {
        match recompute_spec_verified_state(
            &mut spec_store,
            test_store,
            None,
            spec_id,
        ) {
            Ok(true) => verified_spec_ids.push(spec_id.clone()),
            Ok(false) => {},
            Err(error) => errors.push(format!("{}: {}", spec_id, error)),
        }
    }

    (verified_spec_ids, errors)
}

